import{_ as t,o as a,c as r,a5 as o}from"./chunks/framework.BZYO8Bw1.js";const u=JSON.parse('{"title":"Authorization","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/security/authorization.md","filePath":"concepts/security/authorization.md"}'),i={name:"concepts/security/authorization.md"};function n(s,e,c,h,l,p){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="authorization" tabindex="-1">Authorization <a class="header-anchor" href="#authorization" aria-label="Permalink to &quot;Authorization&quot;">​</a></h1><p>Once an identity is established, Platform Mesh must determine what that identity is permitted to do. Given the complexity of interactions across hierarchical accounts, <a href="/pr-preview/pr-233/concepts/personas/service-provider.html">service providers</a>, and <a href="/pr-preview/pr-233/concepts/personas/service-consumer.html">service consumers</a>, Platform Mesh supports a <strong>two-tier authorization model</strong>: Kubernetes RBAC for control-plane-local decisions and OpenFGA for authorization across control plane boundaries.</p><h2 id="kubernetes-native-rbac" tabindex="-1">Kubernetes-native RBAC <a class="header-anchor" href="#kubernetes-native-rbac" aria-label="Permalink to &quot;Kubernetes-native RBAC&quot;">​</a></h2><p>The first tier leverages the built-in Role-Based Access Control<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> mechanism of Kubernetes. Since the Platform Mesh API layer is built on the <a href="/pr-preview/pr-233/concepts/control-planes.html">Kubernetes Resource Model</a> and powered by <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>, RBAC is the natural structural access control layer.</p><p>Kubernetes RBAC operates at the API resource level, governing which subjects (users, groups, service accounts) can perform which verbs (get, list, create, update, delete) on which resource types within a given workspace. Each account functions as an isolated <a href="/pr-preview/pr-233/concepts/control-planes.html">control plane</a> with its own RBAC configuration, meaning access policies are always scoped to the control plane they are defined in. RBAC rules are themselves Kubernetes resources, managed declaratively through the same KRM patterns used for all platform resources, consistent with the <a href="/pr-preview/pr-233/concepts/why-platform-mesh.html">declarative API principle</a>. This extends naturally to Custom Resource Definitions introduced by <a href="/pr-preview/pr-233/concepts/personas/service-provider.html">Managed Service Providers</a>: when a service provider exposes new capabilities, the existing RBAC mechanism governs access without additional configuration.</p><h2 id="fine-grained-authorization-with-rebac" tabindex="-1">Fine-grained authorization with ReBAC <a class="header-anchor" href="#fine-grained-authorization-with-rebac" aria-label="Permalink to &quot;Fine-grained authorization with ReBAC&quot;">​</a></h2><p>The second tier addresses authorization decisions that go beyond what RBAC can express: decisions that depend on relationships between entities such as team memberships, resource ownership, or service subscriptions.</p><p>OpenFGA<sup class="footnote-ref"><a href="#fn2" id="fnref2">[2]</a></sup> provides <strong>Relationship-Based Access Control (ReBAC)</strong>, an authorization model based on the Zanzibar approach<sup class="footnote-ref"><a href="#fn3" id="fnref3">[3]</a></sup>, where access decisions are derived from a graph of relationships rather than static role assignments. Authorization state is expressed as relationship tuples, (user, relation, object), and permissions propagate through the graph. For example, if a team has ordered a service and a user is a member of that team, the user inherits access to that service instance without explicit per-user permission grants.</p><p>The hierarchical <a href="/pr-preview/pr-233/concepts/account-model.html">account model</a> maps naturally to this relationship graph, and permissions defined at a parent account can flow to child accounts through relationship inheritance. Resources from different <a href="/pr-preview/pr-233/concepts/personas/service-provider.html">service providers</a> are represented as distinct resource types in <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>, and access to each is evaluated through the standard SubjectAccessReview mechanism regardless of the provider origin.</p><h2 id="layered-evaluation" tabindex="-1">Layered evaluation <a class="header-anchor" href="#layered-evaluation" aria-label="Permalink to &quot;Layered evaluation&quot;">​</a></h2><p>Kubernetes RBAC serves as the first gate, enforcing structural access at the API level. When RBAC can make a definitive decision (granting or denying access based on resource-type permissions), the request is resolved immediately. When RBAC has no opinion, typically for fine-grained access decisions that depend on relationships rather than resource types, the request is forwarded to OpenFGA through the authorization webhook for relationship-based evaluation.</p><p>OpenFGA is integrated through <a href="https://kcp.io" target="_blank" rel="noreferrer">kcp</a>&#39;s standard <strong>authorization webhook</strong> mechanism. This means that OpenFGA is not a hardwired component: any authorizer conforming to the Kubernetes authorization webhook interface can be configured as an alternative or additional authorization backend, preserving the platform&#39;s commitment to pluggability and decoupling.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./">Security architecture overview</a></li><li><a href="./authentication.html">Authentication</a> — how identity is established before authorization runs</li><li><a href="/pr-preview/pr-233/concepts/identity-and-authorization.html">Identity and authorization</a> — runtime view of the authorizer chain</li><li><a href="/pr-preview/pr-233/reference/components/openfga.html">OpenFGA</a> — reference for the authorization engine component</li></ul><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p><a href="https://kubernetes.io/docs/reference/access-authn-authz/rbac/" target="_blank" rel="noreferrer">Kubernetes RBAC Documentation</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li><li id="fn2" class="footnote-item"><p><a href="https://openfga.dev/" target="_blank" rel="noreferrer">OpenFGA</a> <a href="#fnref2" class="footnote-backref">↩︎</a></p></li><li id="fn3" class="footnote-item"><p><a href="https://research.google/pubs/zanzibar-googles-consistent-global-authorization-system/" target="_blank" rel="noreferrer">Zanzibar: Google&#39;s Consistent, Global Authorization System</a> <a href="#fnref3" class="footnote-backref">↩︎</a></p></li></ol></section>',16)])])}const f=t(i,[["render",n]]);export{u as __pageData,f as default};
